import{_ as t,o as a,c as r,ae as o}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Link Routing Rules (New)","description":"","frontmatter":{"title":"Link Routing Rules (New)","slug":"link-routing-rules-new"},"headers":[],"relativePath":"account-hub/link-routing-rules-new.md","filePath":"account-hub/link-routing-rules-new.md"}'),i={name:"account-hub/link-routing-rules-new.md"};function n(d,e,s,l,h,c){return a(),r("div",null,[...e[0]||(e[0]=[o('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>This article explains how to configure your link settings in Branch. The <strong>Link Controls</strong> page allows you to manage link domains, customize link appearance, and configure routing rules for different platforms and devices.</p><p>To access these settings, go to <strong>Configuration &gt; Link Controls</strong> in Branch.</p><p>The <strong>Link Controls</strong> page contains two tabs:</p><ul><li><strong>Link Appearance</strong> - Configure your link domains, social media previews, and QR code styling.</li><li><strong>Link Routing Rules</strong> - Configure where users are redirected based on their platform and device.</li></ul><p>The <strong>Link Routing Rules</strong> tab contains settings that control where users are redirected based on their platform, device, and app installation status.</p><h3 id="web-routing" tabindex="-1">Web routing <a class="header-anchor" href="#web-routing" aria-label="Permalink to &quot;Web routing&quot;">​</a></h3><p>Configure where to send users when they don&#39;t have your app installed.</p><h4 id="default-url" tabindex="-1">Default URL <a class="header-anchor" href="#default-url" aria-label="Permalink to &quot;Default URL&quot;">​</a></h4><p>Enter your default fallback URL for links that don&#39;t have a specific redirect configured. This is where users will be sent if they don&#39;t have your app and no other redirect applies.</p><h4 id="redirect-allowlist" tabindex="-1">Redirect allowlist <a class="header-anchor" href="#redirect-allowlist" aria-label="Permalink to &quot;Redirect allowlist&quot;">​</a></h4><p>Limit link redirection to specific web domains or URI schemes across your Branch platform. List each of the domains you want to limit redirection to. Wildcard subdomains are supported using <code>*</code>.</p><p>For example, if your allowlist includes <code>branch.io</code>, <code>*.branch.io</code>, and <code>myapp://</code>, your deep links can only redirect to domains like <code>branch.io</code>, <code>dashboard.branch.io</code>, or <code>myapp://</code>.</p><div class="info custom-block"><p class="custom-block-title">Note</p><p>We recommend including the app store domains that are relevant to the way users download your app, such as <code>play.google.com</code> and <code>apps.apple.com</code>.</p></div><h3 id="mobile-routing" tabindex="-1">Mobile routing <a class="header-anchor" href="#mobile-routing" aria-label="Permalink to &quot;Mobile routing&quot;">​</a></h3><p>Configure where to send mobile users based on their platform.</p><h4 id="android" tabindex="-1">Android <a class="header-anchor" href="#android" aria-label="Permalink to &quot;Android&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Setting</th><th>Description</th></tr></thead><tbody><tr><td>Android URI Scheme</td><td>Where to send your user if they have the app installed.</td></tr><tr><td>Android URL</td><td>Where to send users that don&#39;t have the app. This can be the Play Store or a custom link.</td></tr><tr><td>Android Package Name</td><td>Your app&#39;s package name from the Play Store.</td></tr><tr><td>Enable App Links</td><td>App Links will open URLs directly into an app, rather than the usual Link → Browser → App handoff cycle. This requires some setup, but Branch does this for you. You&#39;ll need to provide your SHA256 certificate fingerprints.</td></tr><tr><td>SHA256 Certificate Fingerprints</td><td>Required for App Links. You can add multiple fingerprints by selecting <strong>Add another SHA256 fingerprint</strong>.</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">Note</p><p>The Play Store is for published apps. If your app can&#39;t be located or is a local/dev build, use the Custom URL option.</p></div><h4 id="generate-sha256-cert-fingerprint" tabindex="-1">Generate SHA256 cert fingerprint <a class="header-anchor" href="#generate-sha256-cert-fingerprint" aria-label="Permalink to &quot;Generate SHA256 cert fingerprint&quot;">​</a></h4><p>If you choose to enable App Links, you&#39;ll need to generate a SHA256 cert fingerprint. Use one of the following methods:</p><p><strong>KeyStore file method</strong></p><ol><li>Navigate to your <code>keystore file</code> (used to build the debug and production version of your APK file before it gets deployed).</li><li>Run <code>keytool -list -v -keystore my-release-key.keystore</code> to generate a fingerprint.</li></ol><p><strong>Android Studio method</strong></p><ol><li>In Android Studio, open the Gradle options from the top-right corner of the page by selecting the elephant icon.</li><li>Select the terminal icon. It will say &quot;Execute Gradle Task&quot; when you hover over it.</li><li>Enter <code>gradle signingReport</code> and press Enter/Return.</li><li>Select the cat icon to open logcat. Copy the SHA256 cert fingerprint from logcat at the bottom of Android Studio.</li></ol><h4 id="ios" tabindex="-1">iOS <a class="header-anchor" href="#ios" aria-label="Permalink to &quot;iOS&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Setting</th><th>Description</th></tr></thead><tbody><tr><td>iOS URI Scheme</td><td>Where to send your user if they have the app installed.</td></tr><tr><td>iOS URL</td><td>Where to send users that don&#39;t have the app. This can be the App Store or a custom link.</td></tr><tr><td>App Store ID</td><td>Your app&#39;s ID from the App Store.</td></tr><tr><td>Enable Universal Links</td><td>Universal Links will open URLs directly into an app, rather than the usual Link → Safari → App handoff cycle. This requires some setup, but Branch does this for you. You&#39;ll need to provide your Apple App Prefix and Bundle Identifiers.</td></tr><tr><td>Bundle Identifiers</td><td>Required for Universal Links. Your app&#39;s Bundle IDs from Xcode. You can add multiple identifiers by selecting <strong>Add another Bundle ID</strong>.</td></tr><tr><td>Apple App Prefix</td><td>Required for Universal Links. Retrieve your Apple App Prefix from your Apple Developer account on the App IDs page. Branch only supports one Apple App Prefix with multiple Bundle IDs.</td></tr><tr><td>Enable NativeLink™</td><td>NativeLink™ uses the local device clipboard to provide guaranteed deferred deep linking. Users will be presented with a landing page and CTA that copies the deep link to their clipboard. When the user installs the app, the app will automatically receive the deep link they copied. Requires iOS SDK 1.39.4 or higher and a Pasteboard Check Method call.</td></tr><tr><td>Audience Rule</td><td>When NativeLink™ is enabled, select the appropriate audience for this feature (e.g., All iOS Traffic).</td></tr></tbody></table><h3 id="advanced-settings" tabindex="-1">Advanced settings <a class="header-anchor" href="#advanced-settings" aria-label="Permalink to &quot;Advanced settings&quot;">​</a></h3><p>These settings apply to both web and app links.</p><h4 id="uri-scheme-deep-link-mode" tabindex="-1">URI scheme deep link mode <a class="header-anchor" href="#uri-scheme-deep-link-mode" aria-label="Permalink to &quot;URI scheme deep link mode&quot;">​</a></h4><p>This selector allows you to control how and when Branch uses URI schemes to open your app when Universal Links and Android App Links fail.</p><table tabindex="0"><thead><tr><th>Mode</th><th>Description</th></tr></thead><tbody><tr><td>Conservative</td><td>Conservative mode will never use URI schemes if there is a risk of error messages.</td></tr><tr><td>Intelligent</td><td><strong>Recommended.</strong> Intelligent mode uses Branch data to safely use URI schemes everywhere, with the slight risk of error messages in certain browsers if the app is uninstalled.</td></tr><tr><td>Aggressive</td><td>Aggressive will force URI schemes everywhere, causing users without the app to see error messages in some browsers.</td></tr></tbody></table><h4 id="match-type" tabindex="-1">Match type <a class="header-anchor" href="#match-type" aria-label="Permalink to &quot;Match type&quot;">​</a></h4><p>Setting Match Type determines the matching methodology Branch uses for your links and app.</p><table tabindex="0"><thead><tr><th>Type</th><th>Description</th></tr></thead><tbody><tr><td>Normal</td><td><strong>Recommended.</strong> Branch will make a deep link through install match based on available footprint data.</td></tr><tr><td>Unique</td><td>Branch will only make a deep link through install match if there is a single, unique outstanding footprint. This is mostly for very special circumstances.</td></tr></tbody></table><h4 id="other-advanced-settings" tabindex="-1">Other advanced settings <a class="header-anchor" href="#other-advanced-settings" aria-label="Permalink to &quot;Other advanced settings&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Setting</th><th>Description</th></tr></thead><tbody><tr><td>Analytics mapping with UTM</td><td>When redirecting to a web URL, Branch automatically passes through any values from the following Branch Link analytics tags as UTM parameters: ~campaign → utm_campaign, ~channel → utm_source, ~feature → utm_medium. If these UTM parameters are already detected on the URLs being redirected to, Branch won&#39;t overwrite them.</td></tr><tr><td>Enable link scraping</td><td>Dynamic links will scrape from appended query parameters like $original_url, $fallback_url, and $desktop_url for meta tags. This ensures social link previews populate correctly for dynamic content.</td></tr><tr><td>Retrieve Last Attributed Touch Data via SDKs</td><td>Allows the app to fetch link data through the SDK rather than persisting it locally. Use this to implement post-onboarding or deferred deep linking.</td></tr></tbody></table><h3 id="desktop-redirects" tabindex="-1">Desktop redirects <a class="header-anchor" href="#desktop-redirects" aria-label="Permalink to &quot;Desktop redirects&quot;">​</a></h3><p>Configure where to send users accessing your links from desktop devices.</p><h4 id="default-desktop" tabindex="-1">Default desktop <a class="header-anchor" href="#default-desktop" aria-label="Permalink to &quot;Default desktop&quot;">​</a></h4><p>Select one of the following options:</p><ul><li><strong>Branch-hosted QR Code Landing Page</strong> - Display a QR code that users can scan to open the link on their mobile device.</li><li><strong>Custom Landing Page</strong> - Redirect to a custom URL of your choice.</li></ul><h4 id="mac-desktop" tabindex="-1">Mac desktop <a class="header-anchor" href="#mac-desktop" aria-label="Permalink to &quot;Mac desktop&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Setting</th><th>Description</th></tr></thead><tbody><tr><td>Mac URI Scheme</td><td>The URI scheme to open your Mac app if installed.</td></tr><tr><td>Mac App Store URL</td><td>The URL to your app in the Mac App Store.</td></tr></tbody></table><h4 id="windows-desktop" tabindex="-1">Windows desktop <a class="header-anchor" href="#windows-desktop" aria-label="Permalink to &quot;Windows desktop&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Setting</th><th>Description</th></tr></thead><tbody><tr><td>Windows URI Scheme</td><td>The URI scheme to open your Windows app if installed.</td></tr><tr><td>Windows Store URL</td><td>The URL to your app in the Windows Store.</td></tr><tr><td>Windows Package Family Name</td><td>Your app&#39;s Package Family Name from the Windows Store.</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">Note</p><p>If the app isn&#39;t installed when the link is selected, the user will be redirected to the Desktop URL or Default URL, in that order.</p></div><h3 id="advanced-mobile-redirects" tabindex="-1">Advanced mobile redirects <a class="header-anchor" href="#advanced-mobile-redirects" aria-label="Permalink to &quot;Advanced mobile redirects&quot;">​</a></h3><p>These settings allow you to specify different destination URLs or app store listings for users accessing your content on various mobile devices and platforms.</p><h4 id="amazon-fire-redirects" tabindex="-1">Amazon Fire redirects <a class="header-anchor" href="#amazon-fire-redirects" aria-label="Permalink to &quot;Amazon Fire redirects&quot;">​</a></h4><p>Enter your optional Amazon Fire URL. If blank, users will be redirected to your current Android default setting.</p><p>If you have a different package for the Amazon Store than the Play Store on Fire devices, specify the Amazon Fire URL here using the <code>p=package</code> parameter.</p><h4 id="ipad-redirects" tabindex="-1">iPad redirects <a class="header-anchor" href="#ipad-redirects" aria-label="Permalink to &quot;iPad redirects&quot;">​</a></h4><p>Enter your optional iPad URL. If you have a different App Store ID for your iPad app or would prefer to fall back to a different URL on iPad tablets, specify either URL here.</p><h4 id="android-tablet-redirects" tabindex="-1">Android tablet redirects <a class="header-anchor" href="#android-tablet-redirects" aria-label="Permalink to &quot;Android tablet redirects&quot;">​</a></h4><p>Enter your optional Android Tablet URL. If blank, users will be redirected to your current Android default setting.</p><p>If you have a different Play Store package for your tablet apps or would prefer to fall back to a different URL on Android tablets, specify either URL here.</p><h4 id="wechat-redirects" tabindex="-1">WeChat redirects <a class="header-anchor" href="#wechat-redirects" aria-label="Permalink to &quot;WeChat redirects&quot;">​</a></h4><p>Enter your optional WeChat URL. If blank, users will be redirected to the Default URL.</p><div class="info custom-block"><p class="custom-block-title">Note</p><p>WeChat doesn&#39;t support deep linking out of the app on iOS or Android. If you choose to fall back to a custom URL, you can enter it here.</p></div><h3 id="save-your-changes" tabindex="-1">Save your changes <a class="header-anchor" href="#save-your-changes" aria-label="Permalink to &quot;Save your changes&quot;">​</a></h3><p>After making changes on the <strong>Link Routing Rules</strong> tab, select <strong>Save changes</strong> to apply your settings.</p>',62)])])}const f=t(i,[["render",n]]);export{u as __pageData,f as default};
